import { Message } from '@/types/chat'

interface MessageBubbleProps {
  message: Message
}

export default function MessageBubble({ message }: MessageBubbleProps) {
  const isUser = message.role === 'user'
  
  const formatTime = (date: Date) => {
    return new Intl.DateTimeFormat('en-US', {
      hour: 'numeric',
      minute: '2-digit',
      hour12: true,
    }).format(date)
  }

  return (
    <div
      className={`flex w-full animate-slide-up ${
        isUser ? 'justify-end' : 'justify-start'
      }`}
    >
      <div
        className={`flex flex-col max-w-[85%] sm:max-w-[75%] ${
          isUser ? 'items-end' : 'items-start'
        }`}
      >
        <div
          className={`px-4 py-3 rounded-lg ${
            isUser
              ? 'bg-primary-500 text-white shadow-soft'
              : 'bg-white dark:bg-slate-850 text-neutral-900 dark:text-neutral-50 shadow-soft border border-neutral-200 dark:border-neutral-800'
          }`}
        >
          <p className="text-base leading-relaxed whitespace-pre-wrap break-words">
            {message.content}
          </p>
        </div>
        <span className="text-xs text-neutral-400 dark:text-neutral-500 mt-1.5 px-1">
          {formatTime(message.timestamp)}
        </span>
      </div>
    </div>
  )
}
