import { useState, KeyboardEvent, useRef, useEffect } from 'react'

interface ChatInputProps {
  onSendMessage: (content: string) => void
  disabled?: boolean
}

export default function ChatInput({ onSendMessage, disabled }: ChatInputProps) {
  const [input, setInput] = useState('')
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  const handleSubmit = () => {
    if (input.trim() && !disabled) {
      onSendMessage(input.trim())
      setInput('')
      if (textareaRef.current) {
        textareaRef.current.style.height = 'auto'
      }
    }
  }

  const handleKeyDown = (e: KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSubmit()
    }
  }

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto'
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`
    }
  }, [input])

  return (
    <div className="border-t border-neutral-200 dark:border-neutral-800 bg-white dark:bg-slate-850 px-4 py-4 sm:px-6">
      <div className="max-w-3xl mx-auto">
        <div className="relative flex items-end gap-3">
          <div className="flex-1 relative">
            <textarea
              ref={textareaRef}
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Type your message..."
              disabled={disabled}
              rows={1}
              className="w-full resize-none rounded-lg px-4 py-3 pr-12 text-base
                bg-neutral-50 dark:bg-slate-900
                border border-neutral-200 dark:border-neutral-800
                text-neutral-900 dark:text-neutral-50
                placeholder:text-neutral-400 dark:placeholder:text-neutral-600
                focus:outline-none focus:ring-2 focus:ring-primary-500/40 focus:border-primary-500
                disabled:opacity-50 disabled:cursor-not-allowed
                transition-all duration-200
                shadow-inner-soft
                max-h-32 overflow-y-auto"
            />
            <div className="absolute right-3 bottom-3 text-xs text-neutral-400 dark:text-neutral-600 pointer-events-none">
              <span className="hidden sm:inline">↵ send</span>
            </div>
          </div>
          <button
            onClick={handleSubmit}
            disabled={!input.trim() || disabled}
            className="flex items-center justify-center h-12 w-12 rounded-lg
              bg-primary-500 text-white
              hover:bg-primary-600 active:bg-primary-700
              disabled:bg-neutral-300 dark:disabled:bg-neutral-800 disabled:text-neutral-500
              disabled:cursor-not-allowed
              transition-all duration-200
              shadow-soft hover:shadow-soft-lg
              focus:outline-none focus:ring-2 focus:ring-primary-500/40 focus:ring-offset-2 focus:ring-offset-white dark:focus:ring-offset-slate-850"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 20 20"
              fill="currentColor"
              className="w-5 h-5"
            >
              <path d="M3.105 2.289a.75.75 0 00-.826.95l1.414 4.925A1.5 1.5 0 005.135 9.25h6.115a.75.75 0 010 1.5H5.135a1.5 1.5 0 00-1.442 1.086l-1.414 4.926a.75.75 0 00.826.95 28.896 28.896 0 0015.293-7.154.75.75 0 000-1.115A28.897 28.897 0 003.105 2.289z" />
            </svg>
          </button>
        </div>
        <p className="mt-2 text-xs text-neutral-500 dark:text-neutral-600 text-center">
          Press Enter to send, Shift+Enter for new line
        </p>
      </div>
    </div>
  )
}
